// Inputs:
// - mode: 'single_day' | 'last_n_days' | 'tagged_only'
// - target_tag: tag obrigatória (ex: 'daily-summary')
// - date_tag: tag de data (opcional, para mode='single_day' ex: '2026-05-11')
// - days: número de dias (opcional, para mode='last_n_days' ex: '7')

const inp = $input.first().json;
const mode = inp.mode || 'last_n_days';
const target_tag = inp.target_tag || 'daily-summary';
const date_tag = inp.date_tag || '';
const days = parseInt(inp.days) || 7;

const SUPABASE_URL = 'https://apfngqcnjdfinqwefzcs.supabase.co';
const enc = encodeURIComponent;

const params = [];

// Sempre filtrar por não-expirados
params.push('or=' + enc('(expired.is.null,expired.eq.false)'));

// Selecionar campos relevantes
params.push('select=' + enc('id,summary,details,tags,created_at,source,project,type,importance'));

if (mode === 'single_day') {
  if (!date_tag) {
    return [{ json: { error: 'date_tag obrigatorio para mode=single_day', found: false, count: 0, entries: [], formatted: '' } }];
  }
  const andFilter = '(tags.cs.{' + target_tag + '},tags.cs.{' + date_tag + '})';
  params.push('and=' + enc(andFilter));
  params.push('limit=1');
} else if (mode === 'last_n_days') {
  params.push('tags=' + enc('cs.{' + target_tag + '}'));
  const cutoff = new Date(Date.now() - days * 86400000).toISOString();
  params.push('created_at=' + enc('gte.' + cutoff));
  params.push('order=created_at.desc');
  params.push('limit=' + (days + 5));
} else if (mode === 'tagged_only') {
  params.push('tags=' + enc('cs.{' + target_tag + '}'));
  params.push('order=created_at.desc');
  params.push('limit=20');
}

const fullUrl = SUPABASE_URL + '/rest/v1/memories?' + params.join('&');

return [{ json: { url: fullUrl, mode: mode, target_tag: target_tag, date_tag: date_tag, days: days } }];

const items = $input.all();
const meta = $('Build Query URL').first().json;

// Lidar com diferentes formatos de resposta
let entries = [];
if (items.length === 0) {
  entries = [];
} else if (items.length === 1 && items[0].json) {
  const j = items[0].json;
  if (Array.isArray(j)) {
    entries = j;
  } else if (j.error) {
    return [{ json: { found: false, count: 0, entries: [], formatted: `Erro: ${j.error}`, error: j.error } }];
  } else if (j.id) {
    entries = [j];
  } else {
    entries = [];
  }
} else {
  entries = items.map(i => i.json).filter(j => j && j.id);
}

if (entries.length === 0) {
  return [{ json: { found: false, count: 0, entries: [], formatted: `(sem entries para tag '${meta.target_tag}'${meta.date_tag ? ` + '${meta.date_tag}'` : ''})` } }];
}

// Formatar para inclusão em prompt
const lines = entries.map(e => {
  const date = e.created_at ? e.created_at.substring(0, 10) : 'unknown';
  const tags = Array.isArray(e.tags) ? e.tags.join(', ') : '';
  return `### [${date}] ${e.summary}\n${e.details || '(sem details)'}\n---`;
});

const formatted = `## Memórias por tag: ${meta.target_tag}${meta.date_tag ? ` + ${meta.date_tag}` : ''}\n\n${lines.join('\n\n')}`;

return [{
  json: {
    found: true,
    count: entries.length,
    entries,
    formatted,
    mode: meta.mode,
    target_tag: meta.target_tag
  }
}];
